-- Review the CSV and audit report first. Existing locations are never updated or deleted.
begin;
create temporary table location_backfill_candidates (name text, chain_name text, category text, prefecture text, city text, address text, latitude double precision, longitude double precision, coordinate_source text, coordinate_checked_at date, official_store_id text, official_url text, source_name text, source_url text, source_type text, source_checked_at date, verification_status text, candidate_reason text) on commit drop;
select name, chain_name, category, prefecture, city, address, latitude, longitude, coordinate_source, coordinate_checked_at, official_store_id, official_url, source_name, source_url, source_type, source_checked_at, verification_status, candidate_reason from location_backfill_candidates c
where not exists (select 1 from public.locations l where
  (c.official_store_id is not null and l.official_store_id = c.official_store_id) or
  (c.official_url is not null and l.official_url = c.official_url) or
  (regexp_replace(lower(coalesce(l.name,'')), '[\s　・･#＃()（）\-ー—―]', '', 'g') = regexp_replace(lower(c.name), '[\s　・･#＃()（）\-ー—―]', '', 'g') and regexp_replace(lower(coalesce(l.address,'')), '[\s　,，.。\-−‐ー]', '', 'g') = regexp_replace(lower(c.address), '[\s　,，.。\-−‐ー]', '', 'g'))
) on conflict do nothing;
commit;
